export const 鎮宅辟邪 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    const 連 = (a, b) => {
        const dx = b[0] - a[0], dz = b[1] - a[1], L = Math.hypot(dx, dz), t = 0.4 / L;
        線(p => p.M(X(a[0] + dx * t), Z(a[1] + dz * t)).L(X(b[0] - dx * t), Z(b[1] - dz * t)));
    };
    // 符頭：桿波＋散圈＋乂交圈鏈對
    線(p => p.M(X(0.9), Z(1.4)).C(X(2.5), Z(1.2), X(4.5), Z(1.2), X(6.4), Z(1.35)));
    圈(0.6, 1.45);
    圈(6.7, 1.35);
    for (const [x, z] of [[1.0, 2.6], [2.4, 2.4], [4.0, 2.5], [5.5, 2.4], [6.7, 2.5],
        [1.2, 3.7], [6.6, 3.6]])
        圈(x, z);
    連([2.2, 4.4], [3.6, 5.4]);
    連([3.6, 4.4], [2.2, 5.4]);
    圈(2.2, 4.4);
    圈(3.6, 4.4);
    圈(2.2, 5.4);
    圈(3.6, 5.4);
    連([4.4, 4.3], [5.6, 5.2]);
    連([5.6, 4.3], [4.4, 5.2]);
    圈(4.4, 4.3);
    圈(5.6, 4.3);
    圈(4.4, 5.2);
    圈(5.6, 5.2);
    // 左目梯六箱
    線(p => p.M(X(0.9), Z(6.2)).L(X(0.9), Z(16.2)));
    線(p => p.M(X(3.3), Z(6.15)).L(X(3.3), Z(16.15)));
    for (let i = 0; i <= 6; i++)
        線(p => p.M(X(0.9), Z(6.2 + i * 1.67)).L(X(3.3), Z(6.15 + i * 1.67)));
    // 右柱：鬼曷月形疊（摹形從簡）
    // 鬼形（田＋儿曲）
    線(p => p.M(X(4.4), Z(6.5)).L(X(4.4), Z(7.8)).L(X(6.2), Z(7.75))
        .L(X(6.2), Z(6.45)).L(X(4.35), Z(6.5)));
    線(p => p.M(X(5.3), Z(6.55)).L(X(5.28), Z(7.75)), 0.3);
    線(p => p.M(X(4.7), Z(8.0)).C(X(4.5), Z(8.7), X(4.6), Z(9.2), X(5.0), Z(9.4)), 0.34);
    線(p => p.M(X(5.8), Z(8.0)).C(X(6.0), Z(8.6), X(5.9), Z(9.2), X(5.5), Z(9.5)), 0.34);
    // 曷形（曰＋勹曲）
    線(p => p.M(X(4.4), Z(10.0)).L(X(4.4), Z(11.2)).L(X(6.2), Z(11.15))
        .L(X(6.2), Z(9.95)).L(X(4.35), Z(10.0)));
    線(p => p.M(X(4.5), Z(10.6)).L(X(6.1), Z(10.57)), 0.3);
    線(p => p.M(X(4.6), Z(11.5)).C(X(4.9), Z(12.1), X(5.5), Z(12.3), X(6.0), Z(12.0))
        .C(X(6.3), Z(11.8), X(6.3), Z(12.5), X(5.9), Z(12.8)), 0.34);
    // 月形
    線(p => p.M(X(4.6), Z(13.4)).L(X(4.6), Z(15.8))
        .C(X(4.6), Z(16.2), X(4.4), Z(16.4), X(4.1), Z(16.4)), 0.36);
    線(p => p.M(X(4.65), Z(13.45)).L(X(6.1), Z(13.4)).L(X(6.1), Z(15.9)), 0.36);
    線(p => p.M(X(4.7), Z(14.3)).L(X(6.0), Z(14.27)), 0.3);
    線(p => p.M(X(4.7), Z(15.1)).L(X(6.0), Z(15.07)), 0.3);
    // 底尸尾曲
    線(p => p.M(X(1.3), Z(16.8)).C(X(1.2), Z(17.5), X(1.2), Z(18.1), X(1.3), Z(18.6)));
    線(p => p.M(X(5.3), Z(16.6))
        .C(X(5.0), Z(17.3), X(5.2), Z(17.9), X(5.8), Z(18.0))
        .C(X(6.3), Z(18.1), X(6.5), Z(17.7), X(6.2), Z(17.45)), 0.36);
};
